mapper.select:
SELECT t.* FROM task_item t WHERE t.parent_id IS NULL
AND t.status = #{status}
AND ( EXISTS ( SELECT 1 FROM task_item_assignee a WHERE a.task_id = t.id AND a.user_id = #{userId} AND a.deleted = 0 ) OR t.creator_id = #{userId} OR EXISTS ( SELECT 1 FROM task_follower f WHERE f.task_id = t.id AND f.user_id = #{userId} AND f.deleted = 0 ) OR EXISTS ( SELECT 1 FROM task_list_item i INNER JOIN task_list_member m ON m.list_id = i.list_id AND m.deleted = 0 INNER JOIN task_list l ON l.id = i.list_id AND l.deleted = 0 WHERE i.task_id = t.id AND i.deleted = 0 AND m.user_id = #{userId} AND l.archived = 0 ) ) ORDER BY t.create_time DESC
